elements.algorithm-2411-001:
\caption{The modified IRLS algorithm used in the \pkg{singleRcapture} package} \label{algo-estimation}\DontPrintSemicolon 
lset{1} Initialize with \code{iter}$\leftarrow 1,  oldsymbol{\eta}\leftarrow$\code{start} $,  oldsymbol{W}\leftarrow I, \ell\leftarrow\ell( oldsymbol{ eta})$.\; 
lset{2} Store values from the previous step: $\ell_{-}\leftarrow\ell,  oldsymbol{W}_{-}\leftarrow oldsymbol{W},  oldsymbol{ eta}_{-}\leftarrow oldsymbol{ eta}$ (the last assignment is omitted during the first iteration), and assign values in the current iteration $\displaystyle oldsymbol{\eta}\leftarrow oldsymbol{X}_{	ext{vlm}} oldsymbol{ eta}+ oldsymbol{o},  oldsymbol{W}_{(k)}\leftarrow\mathbb{E}\left[- rac{\partial^{2}\ell}{\partial oldsymbol{\eta}_{(k)}^	op\partial oldsymbol{\eta}_{(k)}}ight],  oldsymbol{Z}_{(k)}\leftarrow oldsymbol{\eta}_{(k)}+ rac{\partial\ell}{\partial oldsymbol{\eta}_{(k)}} oldsymbol{W}_{(k)}^{-1}- oldsymbol{o}_{(k)}$,\; where $ oldsymbol{o}$ denotes offset.\; 
lset{3} Assign the current coefficient value: $ oldsymbol{ eta}\leftarrow\left( oldsymbol{X}_{	ext{vlm}} oldsymbol{W} oldsymbol{X}_{	ext{vlm}}ight)^{-1} oldsymbol{X}_{	ext{vlm}} oldsymbol{W} oldsymbol{Z}$.\; 
lset{4} If $\ell( oldsymbol{ eta})<\ell( oldsymbol{ eta}_{-})$ try selecting the smallest value $h$ such that for $ oldsymbol{ eta}_{h}\leftarrow2^{-h}\left( oldsymbol{ eta}+ oldsymbol{ eta}_{-}ight)$ the inequality $\ell( oldsymbol{ eta}_{h})>\ell( oldsymbol{ eta}_{-})$ holds if this is successful $ oldsymbol{ eta}\leftarrow oldsymbol{ eta}_{h}$, else stop the algorithm.\; 
lset{5} If convergence is achieved or \code{iter} is higher than \code{maxiter}, stop the algorithm, else \code{iter}$\leftarrow 1+$\code{iter} and return to step 2.

elements.algorithm-2411-002:
\caption{Semi-parametric bootstrap} \label{algo-semipar-boot}\DontPrintSemicolon 
lset{1} Draw a sample of size $N_{obs}'\sim	ext{Binomial}\left(N',  rac{N_{obs}}{N'}ight)$, where $N'=\lfloor\hat{N}floor+	ext{Bernoulli}\left(\lfloor\hat{N}floor-\hat{N}ight)$.\; 
lset{2} Draw $N_{obs}'$ units from the data uniformly without replacement.\; 
lset{3} Obtain a new population size estimate $N_b$ using bootstrap data.\; 
lset{4} Repeat $1-3$ steps $B$ times.

elements.algorithm-2411-003:
\caption{Parametric bootstrap} \label{algo-par-boot}\DontPrintSemicolon 
lset{1} Draw the number of covariates equal to $\lfloor\hat{N}floor+	ext{Bernoulli}\left(\lfloor\hat{N}floor-\hat{N}ight)$ proportional to the estimated contribution $(\mathbb{P}\left[Y_{k}>0| oldsymbol{x}_{k}ight])^{-1}$ with replacement.\; 
lset{2} Using the fitted model and regression coefficients $\hat{ oldsymbol{ eta}}$ draw for each covariate the $Y$ value from the corresponding probability measure on $\mathbb{N}\cup\{0\}$.\; 
lset{3} Truncate units with the drawn $Y$ value equal to $0$.\; 
lset{4} Obtain a population size estimate $N_b$ based on the truncated data.\; 
lset{5} Repeat $1-4$ steps $B$ times.
